// Available icon names (alphabetically ordered)
export const NAMES = Object.keys(iconPaths).sort();

/**
 * Check if a value is an external icon reference (URL or path).
 * Extensions can provide custom icons via their static asset routes
 * (e.g., `/api/extensions/:id/static/icon.svg`).
 */
function isExternalIcon(name) {
  return (
    typeof name === 'string' &&
    (name.startsWith('/') || name.startsWith('http'))
  );
}

function Icon({ name, size = 20, className, style, title, ...rest }) {
  const cls = clsx(className);

  // External icon: render as <img> for extension-provided assets
  if (isExternalIcon(name)) {
    return (
      <img
        src={name}
        alt={title || ''}
        width={size}
        height={size}
        className={cls || undefined}
        style={{ objectFit: 'contain', ...style }}
        {...rest}
      />
    );
  }

  const paths = iconPaths[name];

  // Dev-mode warning for unknown icon names
  if (!paths && __DEV__) {
    console.warn(`[Icon] Unknown icon name: "${name}"`);
  }

  // Normalize to array for uniform rendering
  const pathList = paths ? (Array.isArray(paths) ? paths : [paths]) : [];

  return (
    <svg
      width={size}
      height={size}
      viewBox='0 0 24 24'
      fill='none'
      xmlns='http://www.w3.org/2000/svg'
      className={cls || undefined}
      style={style}
      aria-hidden={!title}
      role={title ? 'img' : undefined}
      {...(title ? { 'aria-label': title } : {})}
      {...rest}
    >
      {title && <title>{title}</title>}
      {pathList.map((d, i) => (
        <path
          key={i}
          d={d}
          stroke='currentColor'
          strokeWidth='2'
          strokeLinecap='round'
          strokeLinejoin='round'
          fill='none'
        />
      ))}
    </svg>
  );
}

Icon.propTypes = {
  name: (props, propName, componentName) => {
    const value = props[propName];
    if (value == null) {
      return new Error(
        `The prop \`${propName}\` is marked as required in ` +
          `\`${componentName}\`, but its value is \`${value}\`.`,
      );
    }
    // Allow built-in icon names OR external paths/URLs
    if (
      typeof value === 'string' &&
      (isExternalIcon(value) || NAMES.includes(value))
    ) {
      return null;
    }
    return new Error(
      `Invalid prop \`${propName}\` supplied to \`${componentName}\`. ` +
        `Expected a built-in icon name or an external URL/path. Got: "${value}"`,
    );
  },
  size: PropTypes.number,
  className: PropTypes.string,
  style: PropTypes.object,
  title: PropTypes.string,
};

